INSERT INTO `innovations` VALUES (125,'Green bean ประคบร้อน ผ่อนคลาย สลายปวด','2020-11-11','จากการลงสำรวจข้อมูลของชุมชนลุ่มนา หมู่ที่ 8 ตำบลไทยบุรี อำเภอท่าศาลา จังหวัดนครศรีธรรมราช พบว่า ประชาชนในพื้นที่มีอาการปวดเมื่อยร้อยละ 2.83 ซึ่งสาเหตุส่วนใหญ่มาจากท่าทางการประกอบอาชีพที่ไม่เหมาะสม และส่วนใหญ่เป็นผู้สุงอายุที่มีอาการปวดเมื่อยตามวัย จากเหตุผลดังกล่าวนักศึกษาจึงได้พัฒนานวัตกรรม “Green bean ประคบร้อน ผ่อนคลาย สลายปวด” ขึ้น โดยเน้นการนวด ประคบร้อนเพื่อผ่อนคลายกล้ามเนื้อ ร่วมกับการใช้กลิ่นบำบัดกดจุด  และยังเพิ่มความสะดวกต่อการใช้ โดยผู้ป่วยสามารถใช้ชิ้นงานบรรเทาอาการปวดเมื่อยในขณะปฏิบัติกิจวัตรประจำวันต่างๆได้ สามารถใช้ได้กับอวัยวะทุกส่วนของร่างกาย ผลิตได้ง่ายเนื่องจากเน้นการใช้วัสดุ อุปกรณ์ที่มีในท้องถิ่น รวมถึงลดข้อจำกัดในการใช้อุปกรณ์นำความร้อนจากการใช้เตาอบไมโครเวฟเพียงอย่างเดียว มาเป็นการคั่วเพื่อให้ง่ายต่อการเข้าถึงของคนในชุมชน','ตามไฟล์ที่แนบ','ปัจจัยความสําเร็จ ปัญหา/อุปสรรค พร้อมแนวทางแก้ไข\n	ปัจจัยความสำเร็จ คือ  ได้รับความร่วมมือจากสมาชิกในกลุ่มในการทำชิ้นงาน และคำแนะนำในการปรับปรุงนวัตกรรมจากกลุ่มเป้าหมาย \n	ปัญหา/อุปสรรค คือ สภาพอากาศไม่อำนวย ระยะเวลาในการทำชิ้นงาน การนำไปใช้ และการพัฒนาชิ้นงานไม่ต่อเนื่องกัน \n	การแก้ไข กระชับเวลาในการทำกิจกรรม \nผลการประเมินจากผู้ที่เกี่ยวข้องในการใช้นวัตกรรมบรรเทาอาการปวดเมื่อย\n- เจ้าหน้าที่ “ใช้แล้วรู้สึกอุปกรณ์หาง่าย ทำได้สะดวก สามารถใช้ได้จริง ๆ อาการปวดลดลง”\n- กลุ่มเป้าหมาย “รู้สึกผ่อนคลาย สบาย รู้ปวดเมื่อยลดน้อยลง” “รู้สึกผ่อนคลายมากขึ้น ใช้แล้วทำกิจวัตรประจำวันได้” “ใส่แล้วทำงานได้ ความร้อนกำลังอุ่นพอดี” \n','ผู้ช่วยศาสตราจารย์ธนวรรณ  สงประเสริฐ','เปรียววียา  คงจินดามุณี 	\nศิริลักษณ์  แซ่ย่าง 		\nนิตยา  เปาวะนา 		\nปฐมาวดี  รอดดำ 		\nสุณัฐมน  ยอดระบำ 		\nผาสุก  หวังโสะ 			\n',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(126,'เบาะขนมปัง กดจุดบรรเทาปวด','2020-10-11','จากการทบทวนวรรณกรรม จึงพบเห็นปัญหาที่สำคัญของผู้สูงอายุอย่างหนึ่งคือปัญหาการปวดเมื่อยกล้ามเนื้อ ที่อาจเกิดจากอายุที่เพิ่มมากขึ้น ทำให้การทำงานและระบบต่างๆเสื่อมประสิทธิภาพลง การทำงานหนัก หรือการยกของหนัก ล้วนเป็นสาเหตุที่ทำให้เกิดการปวดมเอยกล้ามเนื้อ และจากภาวะดังกล่าวที่เกิดจากความปวดเมื่อยกล้ามเนื้อ ที่เกิดขึ้นได้ทุกกลุ่มอายุและกลุ่มวัย อาจส่งผลให้เกิดผลกระทบทั้งต่อร่างกายและจิตใจ และด้านการดำเนินชีวิตประจำวัน มีบุคลิกภาพที่เปลี่ยนไป ทำให้มีอาการชาหรืออ่อนแรงของขา และอาจสงผลตอภาวะจิตใจ กอใหเกิดภาวะเครียด หงุดหงิดจากอาการปวด และอาจกอใหเกิดโรคเรื้อรังที่จะตามมาจากอาการปวดหลังได้ ดังนั้นทางกลุ่มจึงได้คิดค้นนวัตกรรมที่มีเชื่อว่า “เบาะขนมปัง กดจุดบรรเทาปวด”','ตามไฟล์ที่แนบ','1. เพื่อให้ผู้เข้าร่วมโครงการร้อยละ 80 มีอาการปวดเมื่อยกล้ามเนื้อลดลงภายใน 2 สัปดาห์\nประสิทธิผล = ผลการปฏิบัติจริง x 100 / เป้าหมาย = 100 x 100 / 80                   \n= 125 %\n\n2.เพื่อให้ผู้เข้าร่วมโครงการร้อยละ 80 มีความพึงพอใจต่อการใช้นวัตกรรมในระดับดีขึ้นไป\nประสิทธิผล = ผลการปฏิบัติจริง x 100 / เป้าหมาย = 100 x 100 / 80                   \n= 125 %\n','ผู้ช่วยศาสตราจารย์ ธนวรรณ  สงประเสริฐ','วิภาดา      เกตุแก้ว         \nปวีณ์สุดา  นิลพัฒน์         \nปุณยาพร  ศรีสองคอน    \nนูรมาวาตี  ดอเลาะ         \nอาวาตีฟ    แนแซ            \nกานต์ธิมา  ศรีอ่อน          \n',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(127,'อุปกรณ์ช่วยผู้ดูแลพลิกตะแคงตัวในผู้ป่วยติดตียงในเขต ตำบลดอนตะโกอำเภอท่าศาลา จังหวัดนครศรีธรรมราช','2020-11-01','1. เพื่อลดความเสี่ยงในการเกิดแผลกดทับในผู้ป่วยติดเตียงหลังจากใช้อุปกรณ์ช่วยพลิกตะแคงตัว\n2. เพื่อให้ผู้ดูแลมีความรู้ในการดูแลผู้ป่วยติดเตียงไม่ให้เกิดแผลกดทับ หลังใช้นวัตกรรม \n3. เพื่อประเมินความพึงพอใจของผู้ดูแลในการใช้อุปกรณ์ช่วยผู้ดูแลพลิกตะแคงตัวในผู้ป่วยที่นอนติดเตียงหลังจากใช้อุปกรณ์\n4. เพื่อประเมินความพึงพอใจของผู้ป่วยติดเตียงในการใช้อุปกรณ์ช่วยผู้ดูแลพลิกตะแคงตัวในผู้ป่วยที่นอนติดเตียงหลังจากใช้อุปกรณ์\n','1. ศึกษาทบทวนวรรณกรรมที่เกี่ยวข้องกับอุปกรณ์ช่วยพลิกตะแคงตัวผู้ป่วยติดเตียง และอุปกรณ์ที่ช่วยลดความเสี่ยงของการเกิดแผลกดทับ \n2. นำเสนอวรรณกรรมที่ทำการศึกษา\n3. ออกแบบนวัตกรรมช่วยพลิกตะแคงตัว และออกแบบชื่อนวัตกรรมเพื่อค้นหาทุนและวัสดุอุปกรณ์ที่จะนำมาใช้ในการออกแบบนวัตกรรม\n4. นำเสนอแก่อาจารย์ประจำกลุ่ม เพื่อขอคำแนะนำและปรับปรุงเพิ่มเติม\n','.1 ผลการประเมินความรู้เกี่ยวกับนวัตกรรม อุปกรณ์ช่วยผู้ดูแลพลิกตะแคงตัวในผู้ป่วยติดเตียง  ก่อน–หลังใช้นวัตกรรม\n	- ก่อนให้ความรู้เกี่ยวกับนวัตกรรมอุปกรณ์ช่วยผู้ดูแลพลิกตะแคงตัวในผู้ป่วยติดเตียง ผู้ดูแลทำแบบทดสอบได้คะแนน 7 คะแนน คิดเป็นร้อยละ70\n	- หลังให้ความรู้เกี่ยวกับนวัตกรรมอุปกรณ์ช่วยผู้ดูแลพลิกตะแคงตัวในผู้ป่วยติดเตียง ผู้ดูแลทำแบบทดสอบได้คะแนน 9 คะแนน คิดเป็นร้อยละ 90\n4.2 ผลการประเมินความพึงพอใจในการใช้นวัตกรรม จากผู้ใช้งานจำนวน 1 คน พบว่า\n	- พึงพอใจขนาด ลักษณะ ความสวยงาม ความคิดริเริ่มสร้างสรรค์ในระดับมากที่สุด\n	- พึงพอใจความทนทานใช้งานได้ต่อเนื่องในระดับมากที่สุด\n	- พึงพอใจนวัตกรรมสามารถช่วยเหลือและลดแรงในขณะพลิกตะแคงตัวผู้ป่วยได้ในระดับมาก\n	- พึงพอใจนวัตกรรมเหมาะสมต่อการใช้งานผู้ป่วยติดเตียงในระดับมากที่สุด\n	- พึงพอใจในภาพรวมนวัตกรรมที่พัฒนาขึ้นในระดับมาก\n','อาจารย์ ดร.นันทพร  กลิ่นจันทร์','ชนกชนม์ เข็มดี     \nพรอริยา ใจดี 	\nฟิรดาว มุมินรุ่งเรืองเดช              \nปานหทัย หนกหลัง 		\nพารีณี แมะแอ 	\nช่อฟ้า พานทอง 	\n	\n',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(128,'อุปกรณ์บริหารกล้ามเนื้อแข็งแรงด้วยตัวเอง','2020-11-11','เนื่องจากร่างกายของผู้สูงอายุจะเกิดการเปลี่ยนแปลงไปในทางที่เสื่อมสภาพตามวัย กล่าวคือ กล้ามเนื้อเหี่ยวลีบเนื่องจากขาดการใช้งาน กล้ามเนื้ออ่อนแรงเนื่องจากความแข็งแรงและความทนของกล้ามเนื้อลดลง ทำให้มีโอกาสลื่นหรือสะดุดได้ง่าย ซึ่งเป็นสาเหตุที่สำคัญในการพลัดตกหกล้มในผู้สูงอายุ นอกจากนี้พบว่าการอ่อนแรงของกล้ามเนื้อเป็นสาเหตุที่สำคัญในการเพิ่มความเสี่ยงในการพลัดตกหกล้ม (ฐิติมา ทาสุวรรณอินทร์, 2562.) หากเกิดการพลัดตกหกล้ม จะได้รับบาดเจ็บและการรักษาที่ต้องใช้ระยะเวลายาวนานมากกว่าวัยอื่น ๆ\nดังนั้นจึงได้คิดค้นและจัดทำนวัตกรรม “อุปกรณ์บริหารกล้ามเนื้อแข็งแรงด้วยตัวเอง (Muscle strong by myself)” ช่วยในการกระดกเท้าขึ้น-ลง ทำให้กล้ามเนื้อที่มีหน้าที่กระดกขึ้น ได้แก่ tibialis anterior, extensor hallucis longus ,extensor digitorum longus, peroneus tertius และกล้ามเนื้อที่มีหน้าที่กดปลายเท้าลง ได้แก่ peroneus longus,  peroneus brevis,  gastrocnemius, soleus, plantaris มีความแข็งแรงมากขึ้น ส่งผลให้ลดความเสี่ยงการพลัดตกหกล้มในผู้สูงอายุ โดยนวัตกรรมสามารถทำให้กระดกเท้าขึ้น-ลงได้ เพื่อให้มีประสิทธิภาพในการยืดและหดกล้ามเนื้อ นอกจากนี้ยังมีความปลอดภัยในการใช้งาน ประหยัดค่าใช้จ่ายได้โดยการนำเอาวัสดุอุปกรณ์ที่มีต้นทุนต่ำมาใช้','โดยใช้กระบวนการ Plan Do Check Action - ตามไฟล์ที่แนบ','ประเมินด้านประสิทธิผล (Effectiveness) \n1.1 เพื่อให้กลุ่มเป้าหมายมีความแข็งแรงของกล้ามเนื้อขาเพิ่มขึ้น ร้อยละ 80\n1.2 เพื่อให้กลุ่มเป้าหมายไม่มีความเสี่ยงต่อการพลัดตกหกล้ม ร้อยละ 80\n1.3 เพื่อให้กลุ่มเป้าหมายมีการใช้นวัตกรรม อย่างน้อยวันละ 30 นาที สัปดาห์ละ  3 วัน ในระยะเวลา 2 สัปดาห์ ร้อยละ 80\n1.4 เพื่อให้กลุ่มเป้าหมายมีความพึงพอใจนวัตกรรมที่ทางกลุ่มได้จัดทำขึ้น ร้อยละ 80\nประเมินด้านประสิทธิภาพ (Efficiency)\nประสิทธิภาพ เนื่องจากผลลัพธ์ที่ได้จากโครงการบรรลุวัตถุประสงค์ มีการใช้งบประมาณทั้งหมด 1,000 บาท จากงบประมาณที่ได้ 1,000 บาท และผู้เข้าร่วมโครงการมีความพึงพอใจมากที่สุด ร้อยละ 100','อาจารย์ ดร.นันทพร  กลิ่นจันทร์','อินทิรา  จีนศรีคง\nวริศรา   สุขไชย	\nวสุวิมล   ชิตวงศ์\nกนกลักษณ์  ประสาน      		\nวฉัตรพร   หนูแก้ว	\nวสิยาพัฐ   อามีน	\n',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(129,'กระเป๋ากันลืม','2020-11-11','จากการศึกษาพบว่า การใช้รูปแบบการติดตามการกินยาของผู้สูงอายุโรคเบาหวานด้วย “ปฏิทินยา เบาหวาน” ทำให้ผู้สูงอายุ สามารถรับประทานยาได้ถูกต้อง คือ ถูกขนาด ถูกเวลา ได้รับยาครบตามแผนการ รักษาของแพทย์ผลการประเมินความพึงพอใจต่อการใช้ปฏิทินยาเบาหวาน มีความพึงพอใจในระดับมาก ที่สุด คิดเป็นร้อยละ 91 อย่างไรก็ตาม ปฏิทินยาเบาหวานยังมีข้อเสนอแนะที่สามารถนำมาปรับปรุงให้ดีขึ้นดังนี้ โดยนำ ตัวเลขและสัญลักษณ์รูปภาพใหม่ พร้อมขนาดตัวอักษรที่ใหญ่ขึ้น แสดงมื้อของการรับประทานยาของผู้ป่วย (เช้า- กลางวัน-เย็น-ก่อนนอน) มาปรับใช้บนฉลากยา เพิ่มความเข้าใจมากยิ่งขึ้น และเลือกใช้สีพื้นหลัง ฉลากยาให้มองเห็นได้ชัดเจนขึ้น\nจากปัญหาดังกล่าวข้างต้นทางคณะผู้จัดทำจึงเห็นความสำคัญของการรับประทานอย่างมีประสิทธิภาพ คือตรงตามแผนการรักษา จึง ได้คิดค้นนวัตกรรม กระเป๋ายากันลืม เพื่อให้การรับประทานยาโรคเป็นไปอย่างมีประสิทธิภาพ\n','ขั้นตอนการดำเนินงาน PDCA  - ตามไฟล์ที่แนบ','ตามไฟล์ที่แนบ','อาจารย์พรชนุตร  ชุมภูนุช','ศิรินันท์ 	เพชรรักษ์ \nนิศาชล 	หมื่นเมือง 	\nศุภนุช 	 ยงยวด 		\nสรัลชนา 	ประดิษฐ์ถาวร 	\nปารินทร์	เมฆปั่น 		\nณัฐฏธิดา 	รอดพันธ์ 	\n',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(130,'แผ่นรองเท้าลดแรงกดทับบริเวณแผลที่ผ่าเท้า','2020-11-01','จากการทบทวนวรรณกรรมโดยนำแนวคิดการลดแรงกดแผลเท้าเบาหวานโดยการใช้ฟองน้ำล้างจานของอาจารย์ชยพล ศิรินิยมชัย เห็นได้ว่าฟองน้ำมีส่วนช่วยในการหายของแผล และจากงานวิจัยของวีณา        ศรีสำราญ พบว่าการใช้หลักการลดแรงกดที่แผล ทำให้แผลไม่รับน้ำหนักขณะเดินหรือการทำให้แผลทำให้แผลลอยพ้นพื้นขณะเดินโดยเว้นช่องบริเวณแผลจากการเจาะรู ทำให้แผลมีโอกาสฟื้นตัว การใส่รองเท้าลดแรงกดที่หาได้ง่าย ขั้นตอนการเจาะรูไม่ยุ่งยาก สามารถใช้ได้ง่าย สะดวก และมีราคาถูก ซึ่งวัสดุเหล่านี้จะช่วยให้แผลไม่ถูกกดทับและนำไปสู่การหายของแผล (วีณา ศรีสำราญ, 2557) ทางกลุ่มจึงได้เลือกใช้ฟองน้ำและโฟมมาเป็นวัสดุในการลดแรงกดทับบริเวณแผลที่ฝ่าเท้า','ตามไฟล์ที่แนบ','ตามไฟล์ที่แนบ','อาจารย์พรชนุตร  ชุมภูนุช','วิลาสินี 		ชูแตง		\nกุลธิดา 		วีระวงศ์	\nนุรอัยณี 		ดาเระมูซอ	\nศรัญญา 		ปานพืช		\nทักษ์ชวนันท์ 	หีดเสน		\nนิสากร 		เดชสงคราม	\n',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(131,'นาฬิกากันลืม','2020-11-23','ทางกลุ่มได้มีการลงสำรวจโดยการสัมภาษณ์จำนวน 11 คนที่ รพ.สต. บ้านทุ่งโหนด รพ.สต. หัวเหมืองทะเล รพ.ต.ปากพูน โรงพยาบาลเทศบาลนครศรีธรรมราช และได้มีการลงสำรวจในหมู่บ้านคลองเกราะ ตำบลโมคลาน อำเภอท่าศาลา จำนวน 93 ครัวเรือน พบจำนวนผู้ป่วยเรื้อรังที่ใช้ยา จำนวน 50 คน ได้แก่ ชาย 12 คน หญิง 38 คน อายุ 0-18 ปี ใช้ยา ร้อยละ 4 , 19-45 ปี ร้อยละ 2 , 46-59 ปี ร้อยละ 22 , 60-69 ปี ร้อยละ 30 , 70-79 ปี ร้อยละ 38 และมากกว่า 80 ปี ร้อยละ 4 ผู้ป่วยที่สามารถอ่านหนังสือได้ ร้อยละ 96 ไม่สามารถอ่านหนังสือได้ ร้อยละ 4 ส่วนใหญ่รับยาที่โรงพยาบาลท่าศาลา ร้อยละ 68 ส่วนใหญ่ใช้ยา 1-2 ชนิด ร้อยละ 52 กินยาตรงเวลา ร้อยละ 84 หยุดยาเอง ร้อยละ 12 ใช้ยาครบ ร้อยละ 88 จัดยาเองส่วนใหญ่ ร้อยละ 92 ซื้อยากินเอง ร้อยละ 36 ใช้ยาสมุนไพร ร้อยละ 26 และส่วนใหญ่ดูวันหมดอายุของยา ร้อยละ 70 รับประทานยาไม่ตรงเวลา ร้อยละ 16.0 รับประทานยาไม่ครบ ร้อยละ 22 จากการรับประทานยาไม่เหมาะสม ส่งผลให้ผู้ป่วยที่เป็นโรคเรื้อรังไม่สามารถควบคุมการดำเนินของโรคได้ตามเป้าหมายที่วางไว้ หรืออาจทำให้เกิดภาวะแทรกซ้อนได้\nจากการศึกษาช่องว่างดังกล่าวทางกลุ่มได้คิดค้นนวัตกรรมที่มีชื่อว่า นาฬิกากันลืม (Medicines Clock) เพื่อให้ผู้สูงอายุใช้ยาถูกขนาด ถูกเวลา ถูกชนิด และถูกวิธี\n','ประยุกต์ใช้แนวคิด Plan Do Check Act : PDCA) ของนวัตกรรม\n- ตามไฟล์ที่แนบ','- ตามไฟล์ที่แนบ','อาจารย์สิทธิพรรณ  เรือนจันทร์','อามีเน๊าะ	บูดี 		\nนูรียะห์ 	กามะ 	     	\nภรณ์ชนก	การะพันธ์   \nอัซมีน 	 จาหลง 	     	\nสุทธิดา 	บุญนูน 	\nปิติพร  	จันทร์หอมกุล	\n',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(132,'60 ก็ไม่ล้ม...ยั่งยืนด้วยยางยืด','2020-11-23','จากข้อมูลที่ได้ศึกษาค้นคว้า ทางกลุ่มจึงมีความสนใจที่จะพัฒนานวัตกรรมการออกกำลังกายในผู้สูงอายุที่มีปัญหาการทรงตัว “60 ก็ไม่ล้ม... ยั่งยืนด้วยยางยืด” โดยมีการส่งเสริมกิจกรรมการออกกำลังกายด้วยยางยืด และมีรูปภาพท่าทางประกอบเพื่อช่วยในการจดจำและมีการประเมินภาวะเสี่ยงที่อาจทำให้เกิดการพลัดตกหกล้ม รวมทั้งการพัฒนาผู้สูงอายุเพื่อเป็นแกนนำในการทำกิจกรรมการออกกำลังกายด้านการทรงตัวที่เหมาะสมกับภาวะเจ็บป่วยในผู้สูงอายุ','ประยุกต์ใช้แนวคิด Plan Do Check Act : PDCA) ของนวัตกรรม\n- ตามไฟล์ที่แนบ','- ตามไฟล์ที่แนบ','อาจารย์สิทธิพรรณ  เรือนจันทร์','วิรัญชนา 	เจียรมาศ 	\nฟารีซา   	สาและ 	\nพัชนี 	ซือมือ 		\nวิภารดา   	 สุตตันตกุล 	\nพรชนก    	 เสรีสมบูรณ์ 	\nสุชาดา	มานพพงศ์ 	\n',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(133,'กล่องส่งเสริมพัฒนาการเด็ก','2020-11-23','สำหรับอุปกรณ์ในการฝึกพัฒนาการด้านต่างๆของทางโรงพยาบาลและรพ.สต. เป็นอุปกรณ์ที่ใช้สำหรับทดสอบเมื่อผู้ปกครองพาเด็กมาตรวจพัฒนาการเท่านั้น ซึ่งอุปกรณ์ที่สามารถให้ผู้ปกครองนำไปฝึกและกระตุ้นพัฒนาการสำหรับเด็กที่มีพัฒนาการล่าช้ายังมีไม่เพียงพอที่จะให้ผู้ปกครองได้นำกลับไปใช้ หรือมีตัวอย่างที่ให้ผู้ปกครองได้นำไปประยุกต์ใช้เองที่บ้าน จึงทำให้เด็กกลุ่มนี้ถูกละเลยการกระตุ้นพัฒนาการจากทางบ้านเนื่องจากไม่มีอุปกรณ์ ทางกลุ่มจึงเห็นความสำคัญของการกระตุ้นพัฒนาการต่อเนื่องที่บ้านโดยออกแบบอุปกรณ์สำหรับการฝึกกล้ามเนื้อมัดใหญ่ เพื่อให้มีกล้ามเนื้อมัดใหญ่มีความแข็งแรงทำงานได้อย่างสัมพันธ์กัน ร่างกายเจริญเติบโตเหมาะสมตามวัย มีสุขนิสัยที่ดี เล่นและทำกิจกรรมร่วมกับผู้อื่นได้ เกิดความสามารถช่วยเหลือตนเองและดำรงชีวิตประจำวันได้เต็มศักยภาพ นอกจากนี้ยังเพื่อใช้ในการประเมินพัฒนาการเด็กในคลินิก และเพื่อให้ผู้ปกครองสามารถนำไปกระตุ้นพัฒนาการเด็กที่บ้านในรายที่สงสัยว่ามีพัฒนาการด้านกล้ามเนื้อมัดใหญ่ล่าช้า ก่อนจะนัดมาประเมินพัฒนาการซ้ำอีก 1 เดือน หลังจากนำนวัตกรรมให้ผู้ปกครองนำไปกระตุ้นพัฒนาการเด็กที่บ้าน',' - ตามไฟล์ที่แนบ',' - ตามไฟล์ที่แนบ','อาจารย์ ดร.อาทิตย์  บุญรอดชู','นลินนิภา       ทองใบ        \nวทิพมาส       อ่องสุทธิ์       \nกวิสรา          จันทร์ภักดี    \nศุภกิจ           เชาวนา       \nวรินดา          บุญญะ        \nวรางค์ศิริ       สูงเรือง         \n',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(134,'หมอนรองท่อออกซิเจน','2020-12-23','ทั้งนี้ในหอผู้ป่วยกุมารเวชกรรม ได้มีนวัตกรรมที่พัฒนาร่วมกับนักศึกษาพยาบาลชั้นปีที่ 4 เมื่อปี 2560 คือ หมอนรองท่อ corrugated tube ซึ่งทำมาจากผ้า และขวดน้ำเกลือ และได้รับการใช้มาอย่างต่อเนื่อง และเกิดความพึงพอใจของเจ้าหน้าที่ แต่ในปัจจุบันนี้นวัตกรรมดังกล่าว มีการชำรุดและเสื่อมสภาพไม่เหมาะกับการใช้งาน วัสดุเดิมทำมาจากผ้ามีความชื่้นเมื่อโดนน้ำอาจจะเป็นแหล่งสะสมของเชื้อโรค ทำให้ไม่น่าใช้งาน และมีจำนวนชิ้นไม่เพียงพอ ','ประยุกต์ใช้แนวคิด PDCA \n- ตามไฟล์ที่แนบ','- ตามไฟลที่แนบ','อาจารย์กนกวรรณ  ตันตระเสนีย์รัตน์\nพว.จันทร์เพ็ญ  สุดคิด','อามีเน๊าะ  บูดี\nนูรียะห์  กามา\nภรณ์ชนก  การะพันธ์\nอัซมีน  จาหลง\nสุทธิดา  บุญนุน\nปิติพร  จันทร์หอมกุล',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(135,'Easy Pain Assessment Scale','2020-11-18','ตามรายงานที่แนบ','ตามรายงานที่แนบ','ตามรายงานที่แนบ','อาจารย์กนกวรรณ  ตันตระเสนีย์รัตน์\nอาจารย์วรรณา  กุมารจันทร์','นุสรา  สิทธิรักษ์\nลลิตา  วิชามูล\nอัฟนาน  หะยียือราเอง\nกิติยา  พันธ์แทน\nปาลิตา  ทองตัด\nอดินันท์  ตะเห\nพว.สุรารักษ์  ศิริคุณ',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(136,'For your ears For your comfort','2021-11-01','-ตามรายงานที่แนบ','ใช้กระบวนการ PDCA','','อาจารย์พัสตราภรณ์  แก้วพะวงค์','นางสาวบุญสิตา  ช่วยสงค์ และคณะ',NULL,NULL,'2026-03-12 05:10:39','2026-03-12 05:10:39'),(137,'Luke มา Dance','2021-11-01','-ตามรายงานที่แนบ','ใช้กระบวนการ PDCA',